VALUES
  ('aboriginal-f0899a01-moex-00097', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-113-06dee816', 'sub-aboriginal-f0899a01-01', NULL, 'single_choice', '居所地在臺北市的甲，在新北市槍擊乙，乙回到基隆住家後死亡。試問下列敘述何者正確？', '["臺北地方法院對於這一個案件沒有管轄權，因臺北只是甲的居所地", "新北地方法院對於這一個案件沒有管轄權，因為乙於基隆死亡", "基隆地方法院對於這一個案件有管轄權，因甲所犯的是最輕本刑3年以上有期徒刑案件", "新北地方法院對於這一個案件有管轄權，因新北市是犯罪地"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:31+00:00", "source_pdf_sha1": "8b6008d70ff4", "answer_pdf_sha1": "64295f7ceaaf", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "507", "s": "0805", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法與刑事訴訟法概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00098', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-113-06dee816', 'sub-aboriginal-f0899a01-01', NULL, 'single_choice', '甲涉嫌犯有強盜罪，檢察官於偵查中向法院聲請羈押甲，甲於羈押審查程序中，未選任辯護人。 試問下列敘述何者正確？', '["法院無須為甲指定辯護人，因偵查中沒有強制辯護規定的適用", "法院無須為甲指定辯護人，因甲涉嫌所犯的不是高等法院管轄第一審的案件", "法院應為甲指定辯護人，因為此為偵查中的羈押程序", "法院應為甲指定辯護人，因甲涉嫌所犯的是最輕本刑3年以上有期徒刑之案件"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:31+00:00", "source_pdf_sha1": "8b6008d70ff4", "answer_pdf_sha1": "64295f7ceaaf", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "507", "s": "0805", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法與刑事訴訟法概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00099', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-113-06dee816', 'sub-aboriginal-f0899a01-01', NULL, 'single_choice', '嫌疑人甲因涉犯強盜罪，於偵查中遭法院裁定羈押。試問下列敘述何者正確？', '["甲不得與其辯護人接見通信，以維護偵查的有效進行", "甲不得與其辯護人接見通信，因甲涉犯的不是最輕本刑10年以上有期徒刑之案件", "甲得與其辯護人接見通信，但檢察官認為必要時，得限制之", "甲得與其辯護人接見通信，但於必要時，得由檢察官向法院聲請，由法院以限制書限制之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:31+00:00", "source_pdf_sha1": "8b6008d70ff4", "answer_pdf_sha1": "64295f7ceaaf", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "507", "s": "0805", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法與刑事訴訟法概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00100', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-113-06dee816', 'sub-aboriginal-f0899a01-01', NULL, 'single_choice', '甲涉嫌犯有賭博罪，嫌疑重大，且無一定之住所或居所。試問下列敘述何者正確？', '["檢察官得不經傳喚，逕行拘提甲，因檢察官於偵查中有拘提的權限", "檢察官得不經傳喚，逕行拘提甲，因其犯罪嫌疑重大，且無一定之住、居所", "檢察官不得逕行拘提甲，因拘提應由法院裁定", "檢察官不得逕行拘提甲，因甲所犯非最輕本刑5年以上有期徒刑之案件"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:31+00:00", "source_pdf_sha1": "8b6008d70ff4", "answer_pdf_sha1": "64295f7ceaaf", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "507", "s": "0805", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法與刑事訴訟法概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00101', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-113-06dee816', 'sub-aboriginal-f0899a01-01', NULL, 'single_choice', '不具司法警察身分的甲發現乙等人正在公園賭博。試問下列敘述何者正確？', '["甲不得逮捕乙，因甲非司法警察官員", "甲不得逮捕乙，因乙所犯非最輕本刑3年以上有期徒刑之案件", "甲得逮捕乙，因乙為現行犯", "甲得逮捕乙，因乙係在公共場所犯罪"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:31+00:00", "source_pdf_sha1": "8b6008d70ff4", "answer_pdf_sha1": "64295f7ceaaf", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "507", "s": "0805", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法與刑事訴訟法概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00102', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-113-06dee816', 'sub-aboriginal-f0899a01-01', NULL, 'single_choice', '司法警察詢問嫌疑人甲時，疏未告知其得保持緘默。詢問中，甲自白犯罪。試問下列敘述何者正確？', '["甲的自白原則上沒有證據能力，除非司法警察非出於惡意，且甲陳述時出於任意", "甲的自白無證據能力，應予排除", "甲的自白有無證據能力，應由法院審酌人權保障及公共利益的均衡維護後決定", "甲的自白有證據能力，因司法警察僅係疏忽而已"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:31+00:00", "source_pdf_sha1": "8b6008d70ff4", "answer_pdf_sha1": "64295f7ceaaf", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "507", "s": "0805", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法與刑事訴訟法概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00103', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-113-06dee816', 'sub-aboriginal-f0899a01-01', NULL, 'single_choice', '司法警察甲依法於某住所的客廳拘提嫌疑人乙。試問下列敘述何者正確？', '["甲得搜索該住所的書桌抽屜、鞋櫃等處", "甲得搜索乙停放在該住所地下室的汽車", "甲得搜索乙的口袋內的皮夾", "甲得搜索住所內其他人的身體"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:31+00:00", "source_pdf_sha1": "8b6008d70ff4", "answer_pdf_sha1": "64295f7ceaaf", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "507", "s": "0805", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法與刑事訴訟法概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00104', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-113-06dee816', 'sub-aboriginal-f0899a01-01', NULL, 'single_choice', '刑事訴訟法第154條規定：「被告未經審判證明有罪確定前，推定其為無罪。犯罪事實應依證據認 定之，無證據不得認定犯罪事實。」試問本項條文適用，下列說明何者正確？', '["法官就被告有利及不利證據負舉證責任", "檢察官就被告自白證據負舉證責任", "被告就其無罪證據負有舉證責任", "被告自白若與事實相符均可作為證據"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:31+00:00", "source_pdf_sha1": "8b6008d70ff4", "answer_pdf_sha1": "64295f7ceaaf", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "507", "s": "0805", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法與刑事訴訟法概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00105', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-113-06dee816', 'sub-aboriginal-f0899a01-01', NULL, 'single_choice', '依刑事訴訟法第88條有關現行犯逮捕之規定，依實務判決下列敘述何者正確？', '["告訴乃論之罪未經有權之人提出告訴前不得先行逮捕", "司法警察可先行附帶搜索後再予以現行犯逮捕", "司法警察可視現行犯當下場景狀況不予逮捕", "司法警察逮捕現行犯後應隨即向檢察官聲請拘票"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:31+00:00", "source_pdf_sha1": "8b6008d70ff4", "answer_pdf_sha1": "64295f7ceaaf", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "507", "s": "0805", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法與刑事訴訟法概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00106', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-113-06dee816', 'sub-aboriginal-f0899a01-01', NULL, 'single_choice', '刑事訴訟法第196條之1第1項規定：「司法警察官或司法警察因調查犯罪嫌疑人犯罪情形及蒐 集證據之必要，得使用通知書通知證人到場詢問。」有關本項條文之適用，下列敘述何者正確？', '["對該證人應權利告知", "該證人可委任辯護人", "該證人若有合理事由可拒絕證言", "該證人可行接見交通權"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:31+00:00", "source_pdf_sha1": "8b6008d70ff4", "answer_pdf_sha1": "64295f7ceaaf", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "507", "s": "0805", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法與刑事訴訟法概要", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL)
